8622 void LoopVectorizationPlanner::buildVPlansWithVPRecipes(ElementCount MinVF,
8623                                                         ElementCount MaxVF) {
8624   assert(OrigLoop->isInnermost() && "Inner loop expected.");
8625 
8626   auto MaxVFTimes2 = MaxVF * 2;
8627   for (ElementCount VF = MinVF; ElementCount::isKnownLT(VF, MaxVFTimes2);) {
8628     VFRange SubRange = {VF, MaxVFTimes2};
8629     if (auto Plan = tryToBuildVPlanWithVPRecipes(SubRange)) {
8630       // Now optimize the initial VPlan.
8631       if (!Plan->hasVF(ElementCount::getFixed(1)))
8632         VPlanTransforms::truncateToMinimalBitwidths(*Plan,
8633                                                     CM.getMinimalBitwidths());
8634       VPlanTransforms::optimize(*Plan);
8635       // TODO: try to put it close to addActiveLaneMask().
8636       // Discard the plan if it is not EVL-compatible
8637       if (CM.foldTailWithEVL() &&
8638           !VPlanTransforms::tryAddExplicitVectorLength(*Plan))
8639         break;
8640       assert(verifyVPlanIsValid(*Plan) && "VPlan is invalid");
8641       VPlans.push_back(std::move(Plan));
8642     }
8643     VF = SubRange.End;
8644   }
