4462 /// how SCEV will treat the given type, for which isSCEVable must return
4463 /// true. For pointer types, this is the pointer index sized integer type.
4464 Type *ScalarEvolution::getEffectiveSCEVType(Type *Ty) const {
4465   assert(isSCEVable(Ty) && "Type is not SCEVable!");
4466 
4467   if (Ty->isIntegerTy())
4468     return Ty;
4469 
4470   // The only other support type is pointer.
4471   assert(Ty->isPointerTy() && "Unexpected non-pointer non-integer type!");
4472   return getDataLayout().getIndexType(Ty);
4473 }
