4479 bool ScalarEvolution::instructionCouldExistWithOperands(const SCEV *A,
4480                                                         const SCEV *B) {
4481   /// For a valid use point to exist, the defining scope of one operand
4482   /// must dominate the other.
4483   bool PreciseA, PreciseB;
4484   auto *ScopeA = getDefiningScopeBound({A}, PreciseA);
4485   auto *ScopeB = getDefiningScopeBound({B}, PreciseB);
4486   if (!PreciseA || !PreciseB)
4487     // Can't tell.
4488     return false;
4489   return (ScopeA == ScopeB) || DT.dominates(ScopeA, ScopeB) ||
4490     DT.dominates(ScopeB, ScopeA);
4491 }
