4586 /// If Expr computes ~A, return A else return nullptr
4587 static const SCEV *MatchNotExpr(const SCEV *Expr) {
4588   const SCEVAddExpr *Add = dyn_cast<SCEVAddExpr>(Expr);
4589   if (!Add || Add->getNumOperands() != 2 ||
4590       !Add->getOperand(0)->isAllOnesValue())
4591     return nullptr;
4592 
4593   const SCEVMulExpr *AddRHS = dyn_cast<SCEVMulExpr>(Add->getOperand(1));
4594   if (!AddRHS || AddRHS->getNumOperands() != 2 ||
4595       !AddRHS->getOperand(0)->isAllOnesValue())
4596     return nullptr;
4597 
4598   return AddRHS->getOperand(1);
4599 }
