4601 /// Return a SCEV corresponding to ~V = -1-V
4602 const SCEV *ScalarEvolution::getNotSCEV(const SCEV *V) {
4603   assert(!V->getType()->isPointerTy() && "Can't negate pointer");
4604 
4605   if (const SCEVConstant *VC = dyn_cast<SCEVConstant>(V))
4606     return getConstant(
4607                 cast<ConstantInt>(ConstantExpr::getNot(VC->getValue())));
4608 
4609   // Fold ~(u|s)(min|max)(~x, ~y) to (u|s)(max|min)(x, y)
4610   if (const SCEVMinMaxExpr *MME = dyn_cast<SCEVMinMaxExpr>(V)) {
4611     auto MatchMinMaxNegation = [&](const SCEVMinMaxExpr *MME) {
4612       SmallVector<const SCEV *, 2> MatchedOperands;
4613       for (const SCEV *Operand : MME->operands()) {
4614         const SCEV *Matched = MatchNotExpr(Operand);
4615         if (!Matched)
4616           return (const SCEV *)nullptr;
4617         MatchedOperands.push_back(Matched);
4618       }
4619       return getMinMaxExpr(SCEVMinMaxExpr::negate(MME->getSCEVType()),
4620                            MatchedOperands);
4621     };
4622     if (const SCEV *Replaced = MatchMinMaxNegation(MME))
4623       return Replaced;
4624   }
4625 
4626   Type *Ty = V->getType();
4627   Ty = getEffectiveSCEVType(Ty);
4628   return getMinusSCEV(getMinusOne(Ty), V);
4629 }
