4631 const SCEV *ScalarEvolution::removePointerBase(const SCEV *P) {
4632   assert(P->getType()->isPointerTy());
4633 
4634   if (auto *AddRec = dyn_cast<SCEVAddRecExpr>(P)) {
4635     // The base of an AddRec is the first operand.
4636     SmallVector<const SCEV *> Ops{AddRec->operands()};
4637     Ops[0] = removePointerBase(Ops[0]);
4638     // Don't try to transfer nowrap flags for now. We could in some cases
4639     // (for example, if pointer operand of the AddRec is a SCEVUnknown).
4640     return getAddRecExpr(Ops, AddRec->getLoop(), SCEV::FlagAnyWrap);
4641   }
4642   if (auto *Add = dyn_cast<SCEVAddExpr>(P)) {
4643     // The base of an Add is the pointer operand.
4644     SmallVector<const SCEV *> Ops{Add->operands()};
4645     const SCEV **PtrOp = nullptr;
4646     for (const SCEV *&AddOp : Ops) {
4647       if (AddOp->getType()->isPointerTy()) {
4648         assert(!PtrOp && "Cannot have multiple pointer ops");
4649         PtrOp = &AddOp;
4650       }
4651     }
4652     *PtrOp = removePointerBase(*PtrOp);
4653     // Don't try to transfer nowrap flags for now. We could in some cases
4654     // (for example, if the pointer operand of the Add is a SCEVUnknown).
4655     return getAddExpr(Ops);
4656   }
4657   // Any other expression must be a pointer base.
4658   return getZero(P->getType());
4659 }
